import React, { useState } from 'react';
import { View, Text, Button, Alert } from 'react-native';
import Purchases from 'react-native-purchases';

const PaymentModule = () => {
  const [isProcessing, setIsProcessing] = useState(false);

  const handlePurchase = async (productId) => {
    try {
      setIsProcessing(true);
      const purchase = await Purchases.purchaseProduct(productId);
      Alert.alert('Success', `You have successfully purchased ${purchase.productIdentifier}`);
    } catch (error) {
      Alert.alert('Error', 'Failed to process the payment');
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <View>
      <Text>In-App Purchase Module</Text>
      <Button
        title="Purchase Product"
        disabled={isProcessing}
        onPress={() => handlePurchase('your_product_id')}
      />
    </View>
  );
};

export default PaymentModule;